using Altinn.App.Core.Features;
using Altinn.Platform.Storage.Interface.Enums;
using Altinn.Platform.Storage.Interface.Models;

namespace Altinn.App.Core.Internal.WorkflowEngine.Commands.ProcessNext.TaskStart;

/// <summary>
/// Removes data elements generated by previous visits to the task being entered (stale PDFs,
/// receipts, and similar regenerable artifacts), mirroring Storage's <c>generatedFromTask</c>
/// cleanup contract on the app side.
///
/// This runs as the second task-start command - after <see cref="UnlockTaskData"/> (elements may be
/// locked from a previous visit) but before <see cref="OnTaskStartingHook"/>,
/// <see cref="CommonTaskInitialization"/> and <see cref="StartTask"/> - so every piece of task-start
/// logic, including app-supplied hooks, reads a clean slate: any element referencing the entering
/// task that is still visible at task start was created by this same transition (i.e. a retried
/// attempt), which is exactly what idempotent task-start logic wants to see.
/// </summary>
internal sealed class CleanupGeneratedFromTask : IWorkflowEngineCommand
{
    public static string Key => "CleanupGeneratedFromTask";

    public string GetKey() => Key;

    public Task<ProcessEngineCommandResult> Execute(ProcessEngineCommandContext context)
    {
        IInstanceDataMutator instanceDataMutator = context.InstanceDataMutator;
        Instance instance = instanceDataMutator.Instance;
        string taskId = instance.Process.CurrentTask.ElementId;

        var dataElements =
            instance
                .Data?.Where(de =>
                    de.References?.Exists(r =>
                        r.Relation == RelationType.GeneratedFrom
                        && r.ValueType == ReferenceType.Task
                        && r.Value == taskId
                    )
                        is true
                )
                .ToList()
            ?? [];

        foreach (var dataElement in dataElements)
        {
            instanceDataMutator.RemoveDataElement(dataElement);
            instance.Data?.Remove(dataElement);
        }

        return Task.FromResult<ProcessEngineCommandResult>(new SuccessfulProcessEngineCommandResult());
    }
}
